/// <summary>
/// The <c>ETGForexReportsContract</c> class is the contract class for Forex report.
/// </summary>
[
    DataContractAttribute
]

public class ETGForexReportsContract implements SysOperationValidatable
{
     FromDate fromDate;
     ToDate  toDate;
     ETGForexType forexType;
     ETGModuleType  moduleType;


}

Method.Source:
/// <summary>
/// Gets or sets the value of the datacontract parameter FromDate.
/// </summary>
/// <param name="_fromDate">
/// The new value of the datacontract parameter fromDate; optional.
/// </param>
/// <returns>
/// The current value of datacontract parameter fromDate.
/// </returns>
[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalstr("@SYS5209")),
    SysOperationDisplayOrderAttribute('1')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

/// <summary>
/// Gets or sets the value of the datacontract parameter ToDate.
/// </summary>
/// <param name="_toDate1">
/// The new value of the datacontract parameter ToDate; optional.
/// </param>
/// <returns>
/// The current value of datacontract parameter ToDate.
/// </returns>
[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalstr("@SYS14656")),
    SysOperationDisplayOrderAttribute('2')
]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

/// <summary>
/// Gets or sets the value of the datacontract parameter Modul.
/// </summary>
/// <param name="_moduleType">
/// The new value of the datacontract parameter ModuleType; optional.
/// </param>
/// <returns>
/// The current value of datacontract parameter ModuleType.
/// </returns>
[
    DataMemberAttribute('Module'),
    SysOperationLabelAttribute(literalstr("@ETG_New:Module")),
    SysOperationDisplayOrderAttribute('3')
]
public ETGModuleType parmModuleType(ETGModuleType _moduleType = moduleType)
{
    moduleType = _moduleType;
    return moduleType;
}

/// <summary>
/// Gets or sets the value of the datacontract parameter ForexType.
/// </summary>
/// <param name="_forexType">
/// The new value of the datacontract parameter ForexType; optional.
/// </param>
/// <returns>
/// The current value of datacontract parameter ForexType.
/// </returns>
[
    DataMemberAttribute('ForexType'),
    SysOperationLabelAttribute(literalstr("@ETG_New:ETGForexType")),
    SysOperationDisplayOrderAttribute('4')
]
public ETGForexType parmForexType(ETGForexType _forexType = forexType)
{
    forexType = _forexType;
    return forexType;
}

public boolean validate()
{
    boolean ret = true;
    if(!fromDate)
    {
        ret = checkFailed("@SubBill:FieldFromDateMustBeFilledIn");
    }
    if(!toDate)
    {
        ret = checkFailed("@SubBill:FieldToDateMustBeFilledIn");
    }
    if(fromDate > toDate)
    {
        ret = checkFailed("@ETG_New:DateValidation");
    }
   return ret;
}
